const incoming = ($json && typeof $json === 'object') ? $json : {};
const root = incoming.body && typeof incoming.body === 'object' && Object.keys(incoming.body).length
  ? incoming.body
  : incoming;

function pick(...vals) {
  for (const v of vals) {
    if (v === undefined || v === null) continue;
    const s = typeof v === 'string' ? v.trim() : v;
    if (typeof s === 'string' && !s) continue;
    return s;
  }
  return undefined;
}

const taskId = pick(root.task_id, root.taskId, root.replication_id, root.replicationId);
if (!taskId) throw new Error('task_id / replication_id is required');
const userId = pick(root.user_id, root.userId);
if (!userId) throw new Error('user_id is required');
const videoUrl = pick(root.video_url, root.videoUrl);
if (!videoUrl) throw new Error('video_url is required');

const outputLanguage = pick(root.output_language, root.language, '简体中文');
const styleId = pick(root.style_id, root.styleId);
const styleSnapshot = typeof root.style_snapshot === 'object' ? root.style_snapshot : null;
if (!styleId || !styleSnapshot) throw new Error('style_id + style_snapshot are required');

return [{
  json: {
    task_id: taskId,
    replication_id: taskId,
    user_id: userId,
    video_url: videoUrl,
    style_id: styleId,
    style_snapshot: styleSnapshot,
    output_language: outputLanguage,
    target_word_count: Number(pick(root.word_count, root.wordCount, 500)) || 500,
    api_key: pick(root.api_key, root.apiKey, ''),
    callback_url: pick(root.callback_url, root.callbackUrl, ''),
    raw_body: root
  }
}];

const transcript = $json?.data?.text || $json?.text || '';
if (!transcript) {
  throw new Error('extract_video_text 返回为空，无法继续');
}
return [{
  json: {
    ...$json,
    transcript,
    structured: {
      transcript,
      scenes: []
    }
  }
}];

